mapper.select:
SELECT bo.id, bo.status, CASE bo.status WHEN 0 THEN '待确认' WHEN 1 THEN '已确认' WHEN 2 THEN '已取消' WHEN 3 THEN '已完成' ELSE '未知状态' END AS status_text, bo.user_id, u.username, bs.target_type, bs.target_id, CASE bs.target_type WHEN 'SCENIC' THEN ss.name WHEN 'ENTERTAINMENT' THEN es.name END AS target_name, bs.slot_date, bs.start_time, bs.end_time, bo.create_time FROM booking_order bo JOIN booking_slot bs ON bo.slot_id = bs.id AND bs.is_deleted = 0
JOIN user u ON bo.user_id = u.id AND u.is_deleted = 0 LEFT JOIN scenic_spot ss ON bs.target_type = 'SCENIC' AND bs.target_id = ss.id AND ss.is_deleted = 0 LEFT JOIN entertainment_item es ON bs.target_type = 'ENTERTAINMENT' AND bs.target_id = es.id AND es.is_deleted = 0 WHERE bo.is_deleted = 0
AND bo.status = #{status}
AND bs.target_type = #{targetType}
ORDER BY bo.create_time DESC
